# Strangler-fig routing middleware for Claude extraction
import os, hashlib
import httpx
from typing import Optional

class ClaudeRouter:
    def __init__(self, claude_service_url: str, rollout_pct: float = 0.0):
        self.claude_service_url = claude_service_url
        self.rollout_pct = rollout_pct  # 0.0 to 1.0
        self._legacy = LegacyClaudeWrapper()

    def should_use_new_service(self, request_id: str) -> bool:
        # Deterministic routing by hashing request ID for consistency
        h = int(hashlib.md5(request_id.encode()).hexdigest(), 16)
        return (h % 100) < int(self.rollout_pct * 100)

    async def complete(self, prompt: str, request_id: str, **kwargs):
        if self.should_use_new_service(request_id):
            async with httpx.AsyncClient(timeout=60.0) as client:
                response = await client.post(
                    f"{self.claude_service_url}/v1/complete",
                    json={"prompt": prompt, "request_id": request_id, **kwargs},
                    headers={"X-Request-Id": request_id},
                )
                response.raise_for_status()
                return response.json()
        else:
            return await self._legacy.complete(prompt, **kwargs)

# Usage: set rollout_pct=0.05 for 5% canary
router = ClaudeRouter(
    claude_service_url=os.environ["CLAUDE_SERVICE_URL"],
    rollout_pct=float(os.environ.get("CLAUDE_ROLLOUT_PCT", "0.0")),
)
